const { execSync } = require('child_process');
const fs = require('fs');

const CHROME_EPOCH_OFFSET_US = 11644473600000000;
const TAIPEI_OFFSET_MS = 8 * 60 * 60 * 1000;

const now = new Date();
const taipeiNow = new Date(now.getTime() + TAIPEI_OFFSET_MS);
const y = taipeiNow.getUTCFullYear();
const m = taipeiNow.getUTCMonth();
const d = taipeiNow.getUTCDate();

const startUtcMs = Date.UTC(y, m, d, 0, 0, 0) - TAIPEI_OFFSET_MS;
const endUtcMs = startUtcMs + 24 * 60 * 60 * 1000;

const startChrome = startUtcMs * 1000 + CHROME_EPOCH_OFFSET_US;
const endChrome = endUtcMs * 1000 + CHROME_EPOCH_OFFSET_US;

const sources = [
  { name: 'chrome', src: '/data/chrome/History', tmp: '/tmp/chrome_history_copy.db' },
  { name: 'edge', src: '/data/edge/History', tmp: '/tmp/edge_history_copy.db' },
];

const results = [];

for (const { name, src, tmp } of sources) {
  try {
    fs.copyFileSync(src, tmp);
    const sql = `SELECT url, title, last_visit_time, visit_count FROM urls WHERE last_visit_time BETWEEN ${startChrome} AND ${endChrome} ORDER BY last_visit_time DESC`;
    const output = execSync(`sqlite3 -json "${tmp}" "${sql}"`, { encoding: 'utf8', maxBuffer: 1024 * 1024 * 20 });
    const rows = output.trim() ? JSON.parse(output) : [];
    for (const row of rows) {
      results.push({
        json: {
          source: name,
          url: row.url,
          title: row.title,
          visitCount: row.visit_count,
          lastVisitTime: new Date((row.last_visit_time - CHROME_EPOCH_OFFSET_US) / 1000).toISOString(),
        },
      });
    }
  } catch (err) {
    results.push({ json: { source: name, _error: String(err.message || err) } });
  } finally {
    if (fs.existsSync(tmp)) fs.unlinkSync(tmp);
  }
}

return results;

const fs = require('fs');

let blacklistDomains = [];
try {
  const raw = fs.readFileSync('/config/domain_blacklist.json', 'utf8');
  const data = JSON.parse(raw);
  for (const key of Object.keys(data)) {
    if (key.startsWith('_')) continue;
    if (Array.isArray(data[key])) blacklistDomains.push(...data[key]);
  }
} catch (err) {
  // no blacklist file -> no exclusions
}

const items = $input.all();
const merged = new Map();

for (const item of items) {
  const { url, title, visitCount, lastVisitTime, source, _error } = item.json;
  if (_error) continue;
  if (!url) continue;
  if (blacklistDomains.some((domain) => domain && url.includes(domain))) continue;
  if (url.includes('music.youtube.com')) continue;

  let category = 'article';
  let videoId = null;

  const watchMatch = url.match(/[?&]v=([a-zA-Z0-9_-]{11})/);
  const shortMatch = url.match(/youtu\.be\/([a-zA-Z0-9_-]{11})/);
  if (url.includes('youtube.com/watch') && watchMatch) {
    category = 'youtube';
    videoId = watchMatch[1];
  } else if (url.includes('youtu.be/') && shortMatch) {
    category = 'youtube';
    videoId = shortMatch[1];
  }

  const existing = merged.get(url);
  if (existing) {
    existing.visitCount += visitCount || 0;
    existing.sources = Array.from(new Set([...existing.sources, source]));
    if (lastVisitTime > existing.lastVisitTime) existing.lastVisitTime = lastVisitTime;
  } else {
    merged.set(url, {
      category,
      videoId,
      url,
      title,
      visitCount: visitCount || 0,
      lastVisitTime,
      sources: [source],
    });
  }
}

return Array.from(merged.values())
  .sort((a, b) => (a.lastVisitTime < b.lastVisitTime ? 1 : -1))
  .map((json) => ({ json }));

const items = $input.all();
const youtubeMap = new Map();
const others = [];

for (const item of items) {
  const data = item.json;
  if (data.category === 'youtube' && data.videoId) {
    const existing = youtubeMap.get(data.videoId);
    if (existing) {
      existing.visitCount += data.visitCount || 0;
      existing.sources = Array.from(new Set([...existing.sources, ...data.sources]));
      if (data.lastVisitTime > existing.lastVisitTime) {
        existing.lastVisitTime = data.lastVisitTime;
        existing.url = data.url;
      }
    } else {
      youtubeMap.set(data.videoId, { ...data });
    }
  } else {
    others.push(data);
  }
}

return [...others, ...youtubeMap.values()]
  .sort((a, b) => (a.lastVisitTime < b.lastVisitTime ? 1 : -1))
  .map((json) => ({ json }));

const items = $input.all();
const videoIds = items
  .map((i) => i.json)
  .filter((d) => d.category === 'youtube' && d.videoId)
  .map((d) => d.videoId);

// videos.list 單次最多支援 50 個 id；個人瀏覽量極少超過此上限，直接截斷即可
// 無影片時帶入一個固定的佔位 ID，避免空 id 參數讓 API 回傳 400 錯誤；
// 此 ID 不會出現在去重後的清單中，因此後面比對時會被自然忽略
const idParam = videoIds.slice(0, 50).join(',') || 'dQw4w9WgXcQ';

return [{ json: { idParam, hasVideos: videoIds.length > 0 } }];

const response = $input.first().json;
const apiItems = Array.isArray(response.items) ? response.items : [];

const metaMap = new Map();
for (const v of apiItems) {
  metaMap.set(v.id, {
    ytTitle: v.snippet?.title,
    channelTitle: v.snippet?.channelTitle,
    categoryId: v.snippet?.categoryId,
    duration: v.contentDetails?.duration,
    description: (v.snippet?.description || '').slice(0, 200),
  });
}

return $('YouTube videoId 去重').all()
  .map((item) => {
    const data = item.json;
    if (data.category === 'youtube' && metaMap.has(data.videoId)) {
      return { json: { ...data, ...metaMap.get(data.videoId) } };
    }
    return { json: data };
  })
  .filter((item) => !(item.json.category === 'youtube' && item.json.categoryId === '10'));

const items = $input.all().map((i) => i.json);
const youtubeItems = items.filter((d) => d.category === 'youtube');
const articleItems = items.filter((d) => d.category === 'article');

const TAIPEI_OFFSET_MS = 8 * 60 * 60 * 1000;
const dateStr = new Date(Date.now() + TAIPEI_OFFSET_MS).toISOString().slice(0, 10);

const youtubeForPrompt = youtubeItems.map((v) => ({
  title: v.ytTitle || v.title,
  channel: v.channelTitle,
  duration: v.duration,
  description: v.description,
  url: v.url,
}));
const articleForPrompt = articleItems.map((a) => ({ title: a.title, url: a.url }));

const userContent = `今天日期：${dateStr}

YouTube 影片清單(共 ${youtubeForPrompt.length} 部)：
${JSON.stringify(youtubeForPrompt, null, 2)}

瀏覽文章清單(共 ${articleForPrompt.length} 篇)：
${JSON.stringify(articleForPrompt, null, 2)}`;

const systemPrompt = `你是使用者的個人數位足跡彙整助理。請根據使用者今天觀看的 YouTube 影片與瀏覽的文章清單，產生一份繁體中文的每日摘要報告，輸出格式為 Markdown，結構如下：

# 今日重點與關鍵字
(2-4 句總覽，點出今天內容的主要主題與關鍵字)

## YouTube 影片
依主題分類條列，每項包含標題、頻道、簡短說明、原始連結

## 瀏覽文章
依主題分類條列，每項包含標題、原始連結

## 觀察與洞察
找出跨項目的關聯或洞察，並可提出延伸學習/閱讀建議

若清單為空，該段落請簡短說明今天沒有相關紀錄。請直接輸出 Markdown 內容，不要加上程式碼區塊標記或額外說明文字。`;

return [{
  json: {
    dateStr,
    requestBody: {
      system_instruction: {
        parts: [{ text: systemPrompt }],
      },
      contents: [
        { role: 'user', parts: [{ text: userContent }] },
      ],
      generationConfig: {
        maxOutputTokens: 4096,
      },
    },
  },
}];

const response = $input.first().json;
const text = response?.candidates?.[0]?.content?.parts?.[0]?.text || '';
const dateStr = $('準備 Gemini 輸入').first().json.dateStr;

return [{ json: { date: dateStr, markdown: text } }];
